* { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: -apple-system, "Inter", sans-serif;
  background: #e8e0f0;
  padding: 40px 30px 60px;
  color: #1d1d1f;
}

/* Header */
.header {
  text-align: center;
  margin-bottom: 40px;
}
.header svg { display: block; margin: 0 auto 10px; }
.header h1 { font-size: 2.5rem; font-weight: 600; }

/* Grid */
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-auto-flow: dense;
  gap: 20px;
  max-width: 960px;
  margin: 0 auto;
}

/* Cards */
.card {
  background: #fff;
  border-radius: 16px;
  padding: 24px;
  box-shadow: 0 2px 12px rgba(0,0,0,0.06);
}
.card h2 {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: 16px;
}
.card h3 {
  font-size: 0.8rem;
  font-weight: 500;
  color: #888;
  margin-bottom: 10px;
}
.card-section {
  border: 1.5px dashed #c8d0e0;
  border-radius: 12px;
  padding: 16px;
  margin-bottom: 12px;
}
.card-section:last-child { margin-bottom: 0; }
.card-cols {
  display: flex;
  gap: 16px;
}
.card-cols > div { flex: 1; min-width: 0; }

/* Spans 2 columns */
.span-2 { grid-column: span 2; }
.span-row-2 { grid-row: span 2; }

/* Helpers */
.row { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; flex-wrap: wrap; }
.row:last-child { margin-bottom: 0; }
.label { font-size: 0.8rem; color: #666; min-width: 50px; }
.vstack { display: flex; flex-direction: column; gap: 8px; }
.center { display: flex; justify-content: center; align-items: center; }

/* Override some puppertino spacing for compact display */
.card .p-btn { margin: 4px; font-size: 14px; }
.card .p-form-text, .card .p-form-text-alt { margin: 4px; font-size: 13px; width: 160px; }
.card .p-form-radio-cont, .card .p-form-checkbox-cont { margin: 0 6px; font-size: 13px; }
.card .p-form-switch { --width: 50px; }
.card .p-segmented-controls { margin-top: 0; }
